'use client'

import {
  cn,
  DismissableLayer,
  Presence,
  useControllableSignal,
  useRovingFocus,
  useSignalEffect,
  useSignals,
} from '@cascivo/core'
import { useId, useRef, type ReactNode } from 'react'
import styles from './fab.module.css'

export interface FabAction {
  /** Stable React key. Provide when `label` may repeat across actions. */
  id?: string
  /** Accessible name and visible label for the speed-dial item. */
  label: string
  icon: ReactNode
  onSelect: () => void
  disabled?: boolean
}

export interface FabProps {
  /** The main button icon. */
  children: ReactNode
  /** Accessible name for the main button (it is icon-only). */
  label: string
  /** Called on press when there is no speed-dial. Ignored when `actions` is set. */
  onClick?: () => void
  /** Speed-dial actions revealed above the button when opened. */
  actions?: FabAction[]
  /** Screen corner to anchor to. */
  position?: 'bottom-end' | 'bottom-start'
  /** Controlled speed-dial open state. */
  open?: boolean
  /** Initial speed-dial open state for uncontrolled use. */
  defaultOpen?: boolean
  /** Called whenever the speed-dial open state should change. */
  onOpenChange?: (open: boolean) => void
  className?: string
}

/**
 * Floating action button anchored to a screen corner. On its own it is a single
 * fixed button; given `actions` it becomes a speed-dial whose main button toggles a
 * role="menu" of secondary actions (vertical roving focus, Escape / outside press to
 * collapse, focus returns to the button). Fixed position honours the safe-area insets;
 * CSS-only motion, no animation library.
 */
export function Fab({
  children,
  label,
  onClick,
  actions,
  position = 'bottom-end',
  open,
  defaultOpen,
  onOpenChange,
  className,
}: FabProps) {
  useSignals()
  const hasDial = actions != null && actions.length > 0
  const [isOpen, setOpen] = useControllableSignal<boolean>({
    value: open,
    defaultValue: defaultOpen ?? false,
    onChange: onOpenChange,
  })

  const roving = useRovingFocus({ orientation: 'vertical', loop: true })
  const fabRef = useRef<HTMLButtonElement>(null)
  const dialRef = useRef<HTMLElement>(null)
  const menuId = useId()

  // Move focus into the dial on open and back to the button on close.
  const wasOpenRef = useRef(false)
  useSignalEffect(() => {
    const next = hasDial && isOpen.value
    if (next && !wasOpenRef.current) {
      dialRef.current
        ?.querySelector<HTMLElement>('[role="menuitem"]:not([aria-disabled="true"])')
        ?.focus()
    } else if (!next && wasOpenRef.current) {
      fabRef.current?.focus()
    }
    wasOpenRef.current = next
  })

  const selectAction = (action: FabAction): void => {
    if (action.disabled) return
    action.onSelect()
    setOpen(false)
  }

  const mainButton = (
    <button
      ref={fabRef}
      type="button"
      aria-label={label}
      className={styles['fab']}
      {...(hasDial
        ? {
            'aria-haspopup': 'menu' as const,
            'aria-expanded': isOpen.value,
            'aria-controls': menuId,
            'data-state': isOpen.value ? 'open' : 'closed',
            onClick: () => setOpen(!isOpen.value),
          }
        : { onClick })}
    >
      <span className={styles['icon']} aria-hidden="true">
        {children}
      </span>
    </button>
  )

  if (!hasDial) {
    return (
      <div className={cn(styles['root'], className)} data-position={position}>
        {mainButton}
      </div>
    )
  }

  return (
    <DismissableLayer
      onDismiss={() => setOpen(false)}
      escapeDismisses={isOpen.value}
      disableOutsidePointer={!isOpen.value}
    >
      <div className={cn(styles['root'], className)} data-position={position}>
        <Presence present={isOpen}>
          <menu
            ref={dialRef as React.Ref<HTMLMenuElement>}
            id={menuId}
            role="menu"
            aria-label={label}
            className={styles['dial']}
          >
            {actions.map((action, index) => {
              const itemProps = roving.getItemProps(index)
              return (
                <li key={action.id ?? index} role="presentation" className={styles['dialItem']}>
                  <button
                    ref={itemProps.ref as React.Ref<HTMLButtonElement>}
                    type="button"
                    role="menuitem"
                    tabIndex={itemProps.tabIndex}
                    aria-disabled={action.disabled || undefined}
                    className={styles['action']}
                    onKeyDown={itemProps.onKeyDown}
                    onFocus={itemProps.onFocus}
                    onClick={() => selectAction(action)}
                  >
                    <span className={styles['actionLabel']}>{action.label}</span>
                    <span className={styles['actionIcon']} aria-hidden="true">
                      {action.icon}
                    </span>
                  </button>
                </li>
              )
            })}
          </menu>
        </Presence>
        {mainButton}
      </div>
    </DismissableLayer>
  )
}

@layer cascivo.component {
  .root {
    position: fixed;
    z-index: var(--cascivo-z-dropdown, 30);
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-3);
    inset-block-end: calc(var(--cascivo-space-6) + env(safe-area-inset-bottom, 0px));

    &[data-position='bottom-end'] {
      inset-inline-end: calc(var(--cascivo-space-6) + env(safe-area-inset-right, 0px));
      align-items: flex-end;
    }

    &[data-position='bottom-start'] {
      inset-inline-start: calc(var(--cascivo-space-6) + env(safe-area-inset-left, 0px));
      align-items: flex-start;
    }
  }

  .fab {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    inline-size: 3.5rem;
    block-size: 3.5rem;
    padding: 0;
    color: var(--cascivo-color-accent-content);
    background: var(--cascivo-color-accent);
    border: none;
    border-radius: var(--cascivo-radius-full, 9999px);
    box-shadow: var(--cascivo-shadow-overlay);
    cursor: pointer;
    transition:
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      box-shadow var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      background: var(--cascivo-color-accent-hover, var(--cascivo-color-accent));
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }
  }

  .icon {
    display: inline-flex;
    inline-size: 1.5rem;
    block-size: 1.5rem;
    /* Rotate the icon (e.g. + → ×) while the speed-dial is open. */
    transition: rotate var(--cascivo-motion-emphasis, 200ms var(--cascivo-ease-out));

    .fab[data-state='open'] & {
      rotate: 45deg;
    }
  }

  .dial {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-2);
    margin: 0;
    padding: 0;
    list-style: none;
    align-items: inherit;

    opacity: 1;
    translate: 0 0;
    transition:
      opacity var(--cascivo-motion-enter),
      translate var(--cascivo-motion-enter);

    &[data-state='closed'] {
      opacity: 0;
      translate: 0 var(--cascivo-space-3);
      transition:
        opacity var(--cascivo-motion-exit),
        translate var(--cascivo-motion-exit);
    }

    @starting-style {
      &[data-state='open'] {
        opacity: 0;
        translate: 0 var(--cascivo-space-3);
      }
    }
  }

  .dialItem {
    display: flex;
  }

  .action {
    display: inline-flex;
    align-items: center;
    gap: var(--cascivo-space-3);
    min-block-size: var(--cascivo-target-min-coarse, 2.75rem);
    padding-block: var(--cascivo-space-2);
    padding-inline: var(--cascivo-space-4);
    color: var(--cascivo-color-text);
    background: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-full, 9999px);
    box-shadow: var(--cascivo-shadow-overlay);
    cursor: pointer;
    transition: background-color var(--cascivo-duration-150) var(--cascivo-ease-out);

    .root[data-position='bottom-start'] & {
      flex-direction: row-reverse;
    }

    &:hover {
      background: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }

    &[aria-disabled='true'] {
      color: var(--cascivo-color-text-muted);
      cursor: not-allowed;
    }
  }

  .actionLabel {
    font-size: var(--cascivo-text-sm);
    white-space: nowrap;
  }

  .actionIcon {
    display: inline-flex;
    inline-size: 1.25rem;
    block-size: 1.25rem;
    color: var(--cascivo-color-accent);
  }

  @media (prefers-reduced-motion: reduce) {
    .dial,
    .icon {
      transition: none;
    }
  }
}
